void run_event_based_simulation(Input input, SimulationData data, unsigned long * vhash_result )
{
	printf("Running baseline event-based simulation...\n");

	unsigned long verification_scalar = 0;

	#pragma omp parallel
	{
		unsigned long local_hash = 0;
		int nthreads = omp_get_num_threads();
		int tid = omp_get_thread_num();

		long total_lookups = input.lookups;
		long chunk_size = total_lookups / nthreads;
		long start_idx = tid * chunk_size;
		long end_idx = (tid == nthreads - 1) ? total_lookups : start_idx + chunk_size;

		for (long i = start_idx; i < end_idx; i++) {
			uint64_t local_seed = STARTING_SEED;
			local_seed = fast_forward_LCG(local_seed, 2*i);

			double E = LCG_random_double(&local_seed);
			int mat  = pick_mat(&local_seed);

			double macro_xs[4] = {0};

			calculate_macro_xs( macro_xs, mat, E, input, data );

			double max = -DBL_MAX;
			int max_idx = 0;
			for(int x = 0; x < 4; x++ )
			{
				if( max < macro_xs[x] )
				{
					max = macro_xs[x];
					max_idx = x;
				}
			}
			local_hash += (max_idx + 1);
		}

		#pragma omp critical
		verification_scalar += local_hash;
	}

	*vhash_result = verification_scalar;
}

void run_event_based_simulation_optimization_1(Input in, SimulationData data, unsigned long * vhash_result)
{
	const char * optimization_name = "Optimization 1 - Material & Energy Sorts + Material-specific Kernels";

	printf("Simulation Kernel:\"%s\"\n", optimization_name);

	printf("Allocating additional data required by kernel...\n");

	double * p_energy_samples = (double *) malloc(in.lookups * sizeof(double));
	int * mat_samples = (int *) malloc(in.lookups * sizeof(int));

	printf("Beginning optimized simulation...\n");

	#pragma omp parallel for
	for(long i = 0; i < in.lookups; i++) {
		uint64_t seed = STARTING_SEED;
		seed = fast_forward_LCG(seed, 2*i);
		p_energy_samples[i] = LCG_random_double(&seed);
		mat_samples[i] = pick_mat(&seed);
	}

	int n_lookups_per_material[12] = {0};
	for(long i = 0; i < in.lookups; i++) {
		n_lookups_per_material[mat_samples[i]]++;
	}

	int * material_indices[12];
	for(int m=0; m<12; m++) {
		material_indices[m] = (int*)malloc(n_lookups_per_material[m] * sizeof(int));
	}

	int counters[12] = {0};
	for(long i=0; i<in.lookups; i++) {
		int m = mat_samples[i];
		material_indices[m][counters[m]++] = i;
	}

	for(int m=0; m<12; m++) {
		int count = n_lookups_per_material[m];
		for(int i=1; i<count; i++) {
			int idx_i = material_indices[m][i];
			double val_i = p_energy_samples[idx_i];
			int j = i-1;
			while(j >= 0) {
				int idx_j = material_indices[m][j];
				if(p_energy_samples[idx_j] > val_i) {
					material_indices[m][j+1] = idx_j;
					j--;
				} else {
					break;
				}
			}
			material_indices[m][j+1] = idx_i;
		}
	}

	unsigned long verification_scalar = 0;

	for(int m = 0; m < 12; m++) {
		int count = n_lookups_per_material[m];
		if(count == 0) continue;

		#pragma omp parallel for reduction(+:verification_scalar)
		for(int k = 0; k < count; k++) {
			long i = material_indices[m][k];

			int mat = mat_samples[i];
			if(mat != m) continue;

			double macro_xs[4] = {0};
			calculate_macro_xs( macro_xs, mat, p_energy_samples[i], in, data );

			double max = -DBL_MAX;
			int max_idx = 0;
			for(int x = 0; x < 4; x++ ) {
				if( max < macro_xs[x] ) {
					max = macro_xs[x];
					max_idx = x;
				}
			}
			verification_scalar += (max_idx + 1);
		}
	}

	for(int m=0; m<12; m++) free(material_indices[m]);
	free(p_energy_samples);
	free(mat_samples);

	*vhash_result = verification_scalar;
}

